import React from 'react';
import { FloatingMenu, FloatingMenuItem } from '@andes/floating-menu';
import PropTypes from 'prop-types';

/** @typedef {(e: React.MouseEvent<HTMLAnchorElement | HTMLButtonElement>, value: string) => void} OnClickHandler */

/**
 * @typedef {Object} ListContent
 * @prop {string} title
 * @prop {string} [description]
 * @prop {string} [href]
 * @prop {OnClickHandler} [onClick]
 * @prop {import('@andes/floating-menu').FloatingMenuItemProps['leftContent']} [leftContent]
 */

/**
 * @typedef {Object} ButtonListContentProps
 * @prop {() => HTMLElement} [appendTo]
 * @prop {string} [dialogSrLabel]
 * @prop {string} id
 * @prop {string} namespace
 * @prop {ListContent[]} listContent
 * @prop {boolean} [visible]
 * @prop {() => void} [onClickOutside]
 * @prop {import('@andes/floating-menu').FloatingMenuProps['popperOptions']} [popperOptions]
 */

/**
 * @type {React.FunctionComponent<ButtonListContentProps
 * & Pick<import('../../floating-menu').FloatingMenuProps,
 * 'id' | 'placement' | 'trigger' | 'className' | 'srLabel' | 'width' | 'onOpen' | 'onClose'>>}
 */
const ButtonListContent = ({
  className,
  dialogSrLabel,
  id,
  listContent,
  namespace,
  onClickOutside,
  placement,
  popperOptions,
  srLabel,
  trigger,
  visible,
  ...props
}) => (
  <FloatingMenu
    className={className}
    dialogSrLabel={dialogSrLabel}
    placement={placement}
    open={visible}
    popperOptions={popperOptions}
    trigger={trigger}
    id={id}
    srLabel={srLabel}
    {...props}
  >
    {listContent.map(({ title, description, href, onClick, leftContent }, i) => (
      <FloatingMenuItem
        id={`${namespace}__menu-item-${i}`}
        href={href}
        className={`${namespace}__menu-item`}
        key={title}
        value={title}
        title={title}
        description={description}
        onClick={onClick}
        leftContent={leftContent}
      />
    ))}
  </FloatingMenu>
);

ButtonListContent.propTypes = {
  appendTo: PropTypes.func,
  className: PropTypes.string,
  dialogSrLabel: PropTypes.string,
  id: PropTypes.string.isRequired,
  listContent: PropTypes.arrayOf(
    PropTypes.shape({
      description: PropTypes.string,
      href: PropTypes.string,
      onClick: PropTypes.func,
      title: PropTypes.string.isRequired,
      leftContent: PropTypes.oneOfType([
        PropTypes.node,
        PropTypes.shape({
          title: PropTypes.string,
          src: PropTypes.string,
          alt: PropTypes.string,
          src2x: PropTypes.string,
        }),
      ]),
    }).isRequired,
  ).isRequired,
  namespace: PropTypes.string.isRequired,
  onClickOutside: PropTypes.func,
  placement: PropTypes.oneOf([
    'bottom',
    'bottom-start',
    'bottom-end',
    'top',
    'top-start',
    'top-end',
    'left',
    'left-start',
    'left-end',
    'right',
    'right-start',
    'right-end',
  ]),
  popperOptions: PropTypes.shape({}),
  srLabel: PropTypes.string,
  trigger: PropTypes.element.isRequired,
  visible: PropTypes.bool,
  width: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
};

export default ButtonListContent;
