import React, { cloneElement } from 'react';
import PropTypes from 'prop-types';
import Button, { ButtonText } from './Button';
import classNames from 'classnames';
import warning from '@andes/common/build/utils/warning';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import { useThemeContext } from '@andes/themes';

const DEFAULT_HIERARCHY = 'loud';

const namespace = 'andes-button';

/** @type {typeof import('..').FloatingActionButton} */
const FloatingActionButton = (props) => {
  const {
    behavior = 'expanded',
    className,
    hierarchy = DEFAULT_HIERARCHY,
    icon,
    size = 'large',
    srLabel,
    text,
    ref,
    ...otherProps
  } = props;

  const { getThemedComponentClasses, themeHash } = useThemeContext();

  warning(
    text || srLabel,
    `<FloatingActionButton> needs some plain text contents for accessibility reasons.
      Please add an 'srLabel' or 'text' prop.`,
  );

  const containerClasses = classNames(
    `${namespace}-fab`,
    `${namespace}-fab--${behavior}`,
    `${namespace}-fab--${hierarchy}`,
    className,
    {
      [`${namespace}-fab--${size}`]: size,
    },
    getThemedComponentClasses?.('fab'),
  );

  const content = (
    <>
      <span className={`${namespace}--icon-container`}>
        {cloneElement(/** @type {React.ReactElement} */ (icon), {
          'aria-hidden': true,
        })}
      </span>
      {text && <ButtonText>{ text }</ButtonText>}
    </>
  );

  return (
    <div
      className={containerClasses}
      data-andes-fab-button-container
      data-andes-fab-button-hierarchy={hierarchy}
      data-andes-fab-button-size={size}
      {...themeHash}
      {...computeDataAndesState({ expanded: behavior === 'expanded', collapsed: behavior === 'collapsed' })}
    >
      <Button
        {...otherProps}
        data-andes-fab-button
        hierarchy={hierarchy}
        size={size}
        srLabel={srLabel || text}
        ref={ref}
      >
        {content}
      </Button>
    </div>
  );
};

FloatingActionButton.displayName = 'FloatingActionButton';

FloatingActionButton.propTypes = {
  behavior: PropTypes.oneOf([
    'expanded',
    'collapsed',
  ]),
  className: PropTypes.string,
  icon: PropTypes.element.isRequired,
  id: PropTypes.string,
  onClick: PropTypes.func,
  size: PropTypes.oneOf(['small', 'large']),
  hierarchy: PropTypes.oneOf(['loud', 'quiet']),
  srLabel: PropTypes.string,
  text: PropTypes.string,
};

export default FloatingActionButton;
