import warning from '@andes/common/build/utils/warning';
import { WARNING_HIERARCHY_VALUE } from '../constants/warning';

/**
 * @param {import('../..').ButtonProps['hierarchy']} [hierarchy]
 */
export const computeHierarchy = (hierarchy) => {
  if (hierarchy === 'transparent') {
    warning(false, WARNING_HIERARCHY_VALUE);

    return 'mute';
  }

  return hierarchy;
};
