import React, { useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import transformToKebabCase from '@andes/common/build/utils/transformToKebabCase';
import Button, { ButtonText } from './Button';
import { useAndesContext, useId } from '@andes/context';
import ButtonListContent from './ButtonListContent';
import enTranslations from '../translations/en/messages.json';
import zhCnTranslations from '../translations/zh-CN/messages.json';
import esArTranslations from '../translations/es-AR/messages.json';
import ptBrTranslations from '../translations/pt-BR/messages.json';

/** @typedef {import('@popperjs/core').ModifierPhases} ModifierPhases */

const namespace = 'andes-button-split';

const ChevronDown = () => (
  <svg width="20px" height="20px" viewBox="0 0 20 20" version="1.1" xmlns="http://www.w3.org/2000/svg" className={`${namespace}__chevron`}>
    <title>Abrir menú de opciones / Mostrar opciones</title>
    <g stroke="none" strokeWidth="1" fill="none" fillRule="evenodd" fillOpacity="0.8">
      <polygon
        fill="currentColor"
        fillRule="nonzero"
        transform="translate(10.000000, 10.000000) rotate(-90.000000) translate(-10.000000, -10.000000) "
        // eslint-disable-next-line max-len
        points="8.4482158 9.99750228 13.243845 5.20187305 12.3953169 4.35334491 6.75115953 9.99750228 12.4003123 15.6466551 13.2488405 14.798127"
      />
    </g>
  </svg>
);

const ChevronUP = () => (
  <svg width="20px" height="20px" viewBox="0 0 20 20" version="1.1" xmlns="http://www.w3.org/2000/svg" className={`${namespace}__chevron`}>
    <title>Cerrar menú de opciones / Ocultar opciones</title>
    <g stroke="none" strokeWidth="1" fill="none" fillRule="evenodd" fillOpacity="0.8">
      <polygon
        fill="currentColor"
        fillRule="nonzero"
        transform="translate(10.001873, 9.995000) rotate(90.000000) translate(-10.001873, -9.995000) "
        // eslint-disable-next-line max-len
        points="8.45008885 9.99250228 13.2457181 5.19687305 12.3971899 4.34834491 6.75303257 9.99250228 12.4021854 15.6416551 13.2507135 14.793127"
      />
    </g>
  </svg>
);

const placement = {
  top: 'top-start',
  bottom: 'bottom-start',
  bottomRight: 'bottom-start',
  topRight: 'top-start',
};

/** @type {typeof import('..').SplitButton} */
const SplitButton = ({
  backgroundType = 'default',
  children,
  className,
  dialogSrLabel,
  disabled,
  hierarchy = 'loud',
  id,
  listContent,
  onClick,
  side = 'bottomRight',
  srLabel,
  ref,
}) => {
  const componentId = useId(id);
  const [showOptions, setShowOptions] = useState(false);

  const { i18n } = useAndesContext(
    '@andes/button',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCnTranslations },
  );

  const show = () => {
    setShowOptions(true);
  };

  const hide = () => {
    setShowOptions(false);
  };

  const classes = classNames(namespace, className);

  const popperOptions = side === 'top' || side === 'bottom' ? {
    modifiers: [
      {
        name: 'sameWidth',
        enabled: true,
        // @ts-expect-error state has any type
        fn: ({ state }) => {
          state.styles.popper.left = `-${state.elements.reference.parentElement.offsetLeft}px`;
          state.styles.popper.width = `${
            state.elements.reference.parentElement.offsetLeft + state.rects.reference.width
          }px`;
        },
        phase: /** @type {ModifierPhases} */ ('beforeWrite'),
        requires: ['computeStyles'],
        // @ts-expect-error state has any type
        effect: ({ state }) => {
          state.elements.popper.style.width = `${
            state.elements.reference.parentElement.offsetLeft + state.elements.reference.clientWidth
          }px`;
        },
      },
    ],
  } : undefined;

  const listClasses = classNames(`${namespace}__menu`, className, {
    [`${namespace}__menu--${transformToKebabCase(side)}`]: side,
  });

  const trigger = () => (
    <Button
      backgroundType={backgroundType}
      className={`${namespace}-chevron`}
      disabled={disabled}
      hierarchy={hierarchy}
      aria-expanded={showOptions}
      srLabel={srLabel || i18n.pgettext(namespace, 'menú desplegable')}
      id={`${componentId}-chevron`}
      data-andes-split-button-trigger
    >
      {!showOptions ? <ChevronDown /> : <ChevronUP />}
    </Button>
  );

  const buttonListContentPlacement = /** @type {'bottom-start' | 'top-start'} */ (placement[`${side}`]);

  return (
    <div
      className={classes}
      ref={ref}
      data-andes-split-button
      data-andes-state={showOptions ? 'expanded' : 'collapsed'}
    >
      <Button
        backgroundType={backgroundType}
        className={`${namespace}-text`}
        disabled={disabled}
        onClick={onClick}
        hierarchy={hierarchy}
        id={`${componentId}-text`}
      >
        <ButtonText>{children}</ButtonText>
      </Button>
      <ButtonListContent
        placement={buttonListContentPlacement}
        dialogSrLabel={dialogSrLabel}
        listContent={listContent}
        visible={showOptions}
        onClickOutside={hide}
        onOpen={show}
        onClose={hide}
        popperOptions={popperOptions}
        trigger={trigger()}
        namespace={namespace}
        id={`${componentId}-menu`}
        srLabel={srLabel || i18n.pgettext(namespace, 'menú desplegable')}
        className={listClasses}
        width={side === 'top' || side === 'bottom' ? '100%' : 'max-content'}
      />
    </div>
  );
};

SplitButton.propTypes = {
  backgroundType: PropTypes.oneOf(['default', 'complexBackground']),
  children: PropTypes.string.isRequired,
  className: PropTypes.string,
  dialogSrLabel: PropTypes.string,
  disabled: PropTypes.bool,
  hierarchy: PropTypes.oneOf([
    'loud',
    'quiet',
  ]),
  id: PropTypes.string,
  listContent: PropTypes.arrayOf(
    PropTypes.shape({
      href: PropTypes.string,
      onClick: PropTypes.func,
      description: PropTypes.string,
      title: PropTypes.string.isRequired,
      leftContent: PropTypes.oneOfType([
        PropTypes.node,
        PropTypes.shape({
          title: PropTypes.string,
          src: PropTypes.string,
          alt: PropTypes.string,
          src2x: PropTypes.string,
        }),
      ]),
    }).isRequired,
  ).isRequired,
  onClick: PropTypes.func,
  side: PropTypes.oneOf([
    'top',
    'bottom',
    'bottomRight',
    'topRight',
  ]),
  srLabel: PropTypes.string,
};

SplitButton.displayName = 'SplitButton';

export default SplitButton;
